3	const NEIGHBOR_OFFSETS: ReadonlyArray<[number, number]> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
10	
11	const neighborsOf = ([x, y]: Cell): Cell[] =>
12	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy] as Cell);
13	
14	export function nextGeneration(liveCells: Cell[]): Cell[] {
15	  const liveSet = new Set(liveCells.map(cellKey));
16	  const isLive = (cell: Cell): boolean => liveSet.has(cellKey(cell));
17	
18	  const countLiveNeighbors = (cell: Cell): number =>
19	    neighborsOf(cell).filter(isLive).length;
20	
21	  const survivors = liveCells.filter((cell) => {
22	    const liveNeighbors = countLiveNeighbors(cell);
23	    return liveNeighbors === 2 || liveNeighbors === 3;
24	  });
25	
26	  const deadNeighborCandidates = new Map(
27	    liveCells
28	      .flatMap(neighborsOf)
29	      .filter((cell) => !isLive(cell))
30	      .map((cell) => [cellKey(cell), cell] as const),
31	  );
32	
33	  const births = [...deadNeighborCandidates.values()].filter(
34	    (cell) => countLiveNeighbors(cell) === 3,
35	  );
36	
37	  return [...survivors, ...births];
