export function nextGeneration(liveCells: Cell[]): Cell[] {
  const liveSet = new Set(liveCells.map(cellKey));
  const isLive = (cell: Cell): boolean => liveSet.has(cellKey(cell));

  const countLiveNeighbors = (cell: Cell): number =>
    neighborsOf(cell).filter(isLive).length;

  const survivors = liveCells.filter((cell) => {
    const liveNeighbors = countLiveNeighbors(cell);
    return liveNeighbors === 2 || liveNeighbors === 3;
  });

  const deadNeighborCandidates = new Map(
    liveCells
      .flatMap(neighborsOf)
      .filter((cell) => !isLive(cell))
      .map((cell) => [cellKey(cell), cell] as const),
  );

  const births = [...deadNeighborCandidates.values()].filter(
    (cell) => countLiveNeighbors(cell) === 3,
  );

  return [...survivors, ...births];
}

