export function nextGeneration(liveCells: Cell[]): Cell[] {
  const liveSet = new Set(liveCells.map(cellKey));
  const isLive = (cell: Cell): boolean => liveSet.has(cellKey(cell));

  const neighborCounts = new Map<string, { cell: Cell; count: number }>();
  for (const liveCell of liveCells) {
    for (const neighbor of neighborsOf(liveCell)) {
      const key = cellKey(neighbor);
      const entry = neighborCounts.get(key);
      if (entry) {
        entry.count += 1;
      } else {
        neighborCounts.set(key, { cell: neighbor, count: 1 });
      }
    }
  }

  return [...neighborCounts.values()]
    .filter(({ cell, count }) => count === 3 || (count === 2 && isLive(cell)))
    .map(({ cell }) => cell);
}

